const items = $input.all();
const onclicks = items[0]?.json?.announcements || [];
const titles = items[0]?.json?.title || [];
const dates = items[0]?.json?.date || [];

const detailPath = "/boardDetail/1002?bbsSeq=";

// 어제 날짜 (KST)
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
kst.setDate(kst.getDate() - 1);
const yyyy = kst.getFullYear();
const mm = String(kst.getMonth() + 1).padStart(2, '0');
const dd = String(kst.getDate()).padStart(2, '0');
let yesterdayStr = `${yyyy}-${mm}-${dd}`;

// yesterdayStr = '2026-07-04'; // ⭐ 테스트용 (확인 후 이 줄 삭제)

return onclicks.map(function (onclick, index) {
  // bbsArticleDet('48669') → 48669 추출
  const m = (onclick || '').match(/bbsArticleDet\('(\d+)'\)/);
  const seq = m ? m[1] : null;

  return {
    json: {
      announcement: seq ? detailPath + seq : null,  // /boardDetail/1002?bbsSeq=48669
      seq: seq,
      title: (titles[index] || '').trim(),
      date: (dates[index] || '').trim()
    }
  };
}).filter(item => item.json.seq && item.json.date === yesterdayStr);

const names = $('리스트 추출2').first().json.attach_file_name || [];
const onclicks = $('리스트 추출2').first().json.attach_file_address || [];
const baseUrl = "https://www.kicox.or.kr";

// 파일명 정리 ([hwpx, 537 KB] 같은 용량표기 제거)
function cleanName(n) {
  return (n || '').replace(/\s*\[[^\]]*\]\s*$/, '').replace(/\s+/g, ' ').trim();
}
// fnFileDownload('149184','seq') → 다운로드 URL
function toUrl(onclick) {
  const m = (onclick || '').match(/fnFileDownload\('([^']+)'\s*,\s*'([^']+)'\)/);
  return m ? `${baseUrl}/api/fnFile/commonFileDownload/${m[1]}/${m[2]}` : null;
}

let noticeFileName = null, noticeFileAddress = null;
const extraNames = [], extraPaths = [];

for (let i = 0; i < names.length; i++) {
  const name = cleanName(names[i]);
  const url = toUrl(onclicks[i]);
  if (!name || !url) continue;

  if (name.toLowerCase().endsWith('.zip')) {
    extraNames.push(name); extraPaths.push(url); continue;
  }
  if (name.includes('공고') && !noticeFileName) {
    noticeFileName = name; noticeFileAddress = url;
  } else {
    extraNames.push(name); extraPaths.push(url);
  }
}
// 공고 파일 없으면 첫 비-zip 파일
if (!noticeFileName) {
  for (let i = 0; i < names.length; i++) {
    const name = cleanName(names[i]);
    const url = toUrl(onclicks[i]);
    if (name && url && !name.toLowerCase().endsWith('.zip')) {
      noticeFileName = name; noticeFileAddress = url; break;
    }
  }
}

return [{
  json: {
    fileName: noticeFileName,
    fileAddress: noticeFileAddress,
    file_nm: extraNames.join('@'),
    flpth_nm: extraPaths.join('@')
  }
}];

// Loop over input items
for (const item of $input.all()) {
  // 괄호 제거
  if (item.json.pblanc_nm) {
    item.json.pblanc_nm = item.json.pblanc_nm.replace(/[\(\[][^()\[\]]+[\)\]]/g, '').trim();
  }

  // 새 필드 추가
  item.json.myNewField = 1;
}

return $input.all();

let title = $input.first().json.title[0] || '';

// 괄호 또는 대괄호 안의 내용 제거
title = title.replace(/[\(\[][^()\[\]]+[\)\]]/g, '').trim();

return [
  {
    json: {
      title
    }
  }
];

// Function 노드 안
return [
  {
    json: {
      workflowName: $workflow.name,
      insertId: $input.first().json?.data?.insertId ?? null
    }
  }
];

for (const item of $input.all()) {
  for (const k of ['reqst_begin_dt', 'reqst_end_dt']) {
    if (!item.json[k]) item.json[k] = null;
  }
}
return $input.all();

const pages = $input.first().json.pages;
let combinedMarkdown = '';

for (const page of pages) {
  combinedMarkdown += page.markdown + '\n';  // 줄바꿈 포함해서 합치기
}

// 생성일자: KST 기준 현재 시각
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);

const yyyy = kst.getFullYear();
const mm = String(kst.getMonth() + 1).padStart(2, '0');
const dd = String(kst.getDate()).padStart(2, '0');
const hh = String(kst.getHours()).padStart(2, '0');
const min = String(kst.getMinutes()).padStart(2, '0');
const ss = String(kst.getSeconds()).padStart(2, '0');

const formatted = `${yyyy}-${mm}-${dd} ${hh}:${min}:${ss}`;

// 통합 결과 반환
return [
  {
    json: {
      combinedMarkdown,
      creat_p_nttm: formatted,
      created_ts: formatted
    }
  }
];

